/// MAINFILE
fn p_mainfile(state: &mut ProgramState) {
    tspfile_open_output(state);
    tspfile_close(state);
    tspfile_open_io(state);
    {
        let _bytes = b"99";
        let _len = _bytes.len();
    }
    tspfile_read(state);
    if { let _s = format!("{}", state.cust_stat); _s.trim().to_string() } != "10".to_string() {
        println!("{}{}{}", "Error ", state.cust_stat, " on read of empty file");
        { let _ = state._fh_tspfile.close();
            let _ = state._fh_tstfile.close();
            let _ = state._fh_flatfile.close();
            std::process::exit(0); }
    }
    state.tspfl_record = Default::default();
    // START TSPFILE
    tspfile_read(state);
    if { let _s = format!("{}", state.cust_stat); _s.trim().to_string() } != "46".to_string() {
        println!("{}{}{}", "Error ", state.cust_stat, " start/read of empty file");
        { let _ = state._fh_tspfile.close();
            let _ = state._fh_tstfile.close();
            let _ = state._fh_flatfile.close();
            std::process::exit(0); }
    }
    println!("{}", "OK: Operations on empty file");
    tspfile_close(state);
    p_loadfile(state);
    p_listfile(state);
    tstfile_open_input(state);
    if { let _s = format!("{}", state.cust_stat); _s.trim().to_string() } != "00".to_string() {
        println!("{}{}{}", "Expected ERROR ", state.cust_stat, " opening TSTFILE, Record size different");
    } else {
        println!("{}", "Un-Expected open TSTFILE, Record size different");
        tstfile_close(state);
    }
    p_loadflat(state);
    { let _ = state._fh_tspfile.close();
        let _ = state._fh_tstfile.close();
        let _ = state._fh_flatfile.close();
        std::process::exit(0); }
}

