/// OPEN INPUT TSPFILE
fn tspfile_open_input(state: &mut ProgramState) {
    let path = std::env::var("TSPFILE").unwrap_or("tspfile.dat".to_string());
    match CobolFile::open_input(&path) {
        Ok(handle) => { state._fh_tspfile = handle; state._fs_tspfile = FileStatus::Success; }
        Err(_) => { state._fs_tspfile = FileStatus::Error("35".to_string()); }
    }
    { let _s = format!("{}", state._fs_tspfile); let _b = _s.as_bytes(); unsafe { let p = &mut state.cust_stat as *mut _ as *mut u8; for i in 0.._b.len().min(2) { *p.add(i) = _b[i]; } } }
}

/// OPEN OUTPUT TSPFILE
fn tspfile_open_output(state: &mut ProgramState) {
    let path = std::env::var("TSPFILE").unwrap_or("tspfile.dat".to_string());
    match CobolFile::open_output(&path) {
        Ok(handle) => { state._fh_tspfile = handle; state._fs_tspfile = FileStatus::Success; }
        Err(_) => { state._fs_tspfile = FileStatus::Error("35".to_string()); }
    }
    { let _s = format!("{}", state._fs_tspfile); let _b = _s.as_bytes(); unsafe { let p = &mut state.cust_stat as *mut _ as *mut u8; for i in 0.._b.len().min(2) { *p.add(i) = _b[i]; } } }
}

/// READ TSPFILE
fn tspfile_read(state: &mut ProgramState) -> Result<(), FileStatus> {
    match state._fh_tspfile.read_line() {
        Ok(line) => {
            let _bytes = line.as_bytes();
            let _len = _bytes.len().min(177);
            if _len > 0 { let _end = _len.min(0+3); state.cm_cust_pre = FixedString::from(String::from_utf8_lossy(&_bytes[0.._end])); }
            if _len > 3 { let _end = _len.min(3+5); state.cm_cust_nnn = FixedString::from(String::from_utf8_lossy(&_bytes[3.._end])); }
            if _len > 8 { let _end = _len.min(8+1); state.cm_status = FixedString::from(String::from_utf8_lossy(&_bytes[8.._end])); }
            if _len > 9 { let _end = _len.min(9+25); state.cm_company = FixedString::from(String::from_utf8_lossy(&_bytes[9.._end])); }
            if _len > 34 { let _end = _len.min(34+25); state.cm_address_1 = FixedString::from(String::from_utf8_lossy(&_bytes[34.._end])); }
            if _len > 59 { let _end = _len.min(59+25); state.cm_address_2 = FixedString::from(String::from_utf8_lossy(&_bytes[59.._end])); }
            if _len > 84 { let _end = _len.min(84+25); state.cm_address_3 = FixedString::from(String::from_utf8_lossy(&_bytes[84.._end])); }
            if _len > 109 { let _end = _len.min(109+10); let _s = String::from_utf8_lossy(&_bytes[109.._end]).trim().to_string(); state.cm_telephone = _s.parse().unwrap_or_default(); }
            if _len > 119 { let _end = _len.min(119+25); state.cm_dp_mgr = FixedString::from(String::from_utf8_lossy(&_bytes[119.._end])); }
            if _len > 144 { let _end = _len.min(144+8); state.cm_machine = FixedString::from(String::from_utf8_lossy(&_bytes[144.._end])); }
            if _len > 152 { let _end = _len.min(152+4); state.cm_memory = FixedString::from(String::from_utf8_lossy(&_bytes[152.._end])); }
            if _len > 156 { let _end = _len.min(156+8); state.cm_disk = FixedString::from(String::from_utf8_lossy(&_bytes[156.._end])); }
            if _len > 164 { let _end = _len.min(164+8); state.cm_tape = FixedString::from(String::from_utf8_lossy(&_bytes[164.._end])); }
            if _len > 172 { let _end = _len.min(172+5); let _s = String::from_utf8_lossy(&_bytes[172.._end]).trim().to_string(); state.cm_no_terminals = _s.parse().unwrap_or_default(); }
            state._fs_tspfile = FileStatus::Success;
    { let _s = format!("{}", state._fs_tspfile); let _b = _s.as_bytes(); unsafe { let p = &mut state.cust_stat as *mut _ as *mut u8; for i in 0.._b.len().min(2) { *p.add(i) = _b[i]; } } }
        }
        Err(FileStatus::AtEnd) => {
            state._fs_tspfile = FileStatus::AtEnd;
    { let _s = format!("{}", state._fs_tspfile); let _b = _s.as_bytes(); unsafe { let p = &mut state.cust_stat as *mut _ as *mut u8; for i in 0.._b.len().min(2) { *p.add(i) = _b[i]; } } }
        }
        Err(e) => {
            state._fs_tspfile = e.clone();
    { let _s = format!("{}", state._fs_tspfile); let _b = _s.as_bytes(); unsafe { let p = &mut state.cust_stat as *mut _ as *mut u8; for i in 0.._b.len().min(2) { *p.add(i) = _b[i]; } } }
        }
    }
    Ok(())
}

/// WRITE to TSPFILE
fn tspfile_write(state: &mut ProgramState) {
    let mut _buf = vec![b' '; 177];
    { let _src = state.cm_cust_pre.as_bytes(); let _end = (0+3).min(_buf.len()); let _cl = _src.len().min(_end-0); _buf[0..0+_cl].copy_from_slice(&_src[.._cl]); }
    { let _src = state.cm_cust_nnn.as_bytes(); let _end = (3+5).min(_buf.len()); let _cl = _src.len().min(_end-3); _buf[3..3+_cl].copy_from_slice(&_src[.._cl]); }
    { let _src = state.cm_status.as_bytes(); let _end = (8+1).min(_buf.len()); let _cl = _src.len().min(_end-8); _buf[8..8+_cl].copy_from_slice(&_src[.._cl]); }
    { let _src = state.cm_company.as_bytes(); let _end = (9+25).min(_buf.len()); let _cl = _src.len().min(_end-9); _buf[9..9+_cl].copy_from_slice(&_src[.._cl]); }
    { let _src = state.cm_address_1.as_bytes(); let _end = (34+25).min(_buf.len()); let _cl = _src.len().min(_end-34); _buf[34..34+_cl].copy_from_slice(&_src[.._cl]); }
    { let _src = state.cm_address_2.as_bytes(); let _end = (59+25).min(_buf.len()); let _cl = _src.len().min(_end-59); _buf[59..59+_cl].copy_from_slice(&_src[.._cl]); }
    { let _src = state.cm_address_3.as_bytes(); let _end = (84+25).min(_buf.len()); let _cl = _src.len().min(_end-84); _buf[84..84+_cl].copy_from_slice(&_src[.._cl]); }
    { let _s = format!("{:>width$}", state.cm_telephone, width = 10); let _b = _s.as_bytes(); let _cl = _b.len().min(10); _buf[109..109+_cl].copy_from_slice(&_b[_b.len()-_cl..]); }
    { let _src = state.cm_dp_mgr.as_bytes(); let _end = (119+25).min(_buf.len()); let _cl = _src.len().min(_end-119); _buf[119..119+_cl].copy_from_slice(&_src[.._cl]); }
    { let _src = state.cm_machine.as_bytes(); let _end = (144+8).min(_buf.len()); let _cl = _src.len().min(_end-144); _buf[144..144+_cl].copy_from_slice(&_src[.._cl]); }
    { let _src = state.cm_memory.as_bytes(); let _end = (152+4).min(_buf.len()); let _cl = _src.len().min(_end-152); _buf[152..152+_cl].copy_from_slice(&_src[.._cl]); }
    { let _src = state.cm_disk.as_bytes(); let _end = (156+8).min(_buf.len()); let _cl = _src.len().min(_end-156); _buf[156..156+_cl].copy_from_slice(&_src[.._cl]); }
    { let _src = state.cm_tape.as_bytes(); let _end = (164+8).min(_buf.len()); let _cl = _src.len().min(_end-164); _buf[164..164+_cl].copy_from_slice(&_src[.._cl]); }
    { let _s = format!("{:>width$}", state.cm_no_terminals, width = 5); let _b = _s.as_bytes(); let _cl = _b.len().min(5); _buf[172..172+_cl].copy_from_slice(&_b[_b.len()-_cl..]); }
    match state._fh_tspfile.write_record(&_buf) {
        Ok(()) => state._fs_tspfile = FileStatus::Success,
        Err(e) => state._fs_tspfile = e,
    }
}

/// CLOSE TSPFILE
